class MyQueue:

    def __init__(self):
        self.stack1 = []
        self.stack2 = []

    def push(self, x: int) -> None:
        self.stack1.append(x)

    def pop(self) -> int:
        self.shift_stacks()
        return self.stack2.pop()

    def peek(self) -> int:
        self.shift_stacks()
        return self.stack2[-1]

    def empty(self) -> bool:
        return len(self.stack1) == 0 and len(self.stack2) == 0

    def shift_stacks(self):
        if not self.stack2:
            while self.stack1:
                self.stack2.append(self.stack1.pop())

